// ─── Helper ────────────────────────────────────────────────────

export function translateSpell(
  lang: string,
  esName: string,
  esSchool: string,
  esDesc: string,
): SpellTranslation {
  if (lang === "en") return SPELLS_EN[esName] ?? { name: esName, school: esSchool, desc: esDesc };
  if (lang === "pt") return SPELLS_PT[esName] ?? { name: esName, school: esSchool, desc: esDesc };
  return { name: esName, school: esSchool, desc: esDesc };
}

export function translateSchool(lang: string, esSchool: string): string {
  if (lang === "en") return SCHOOL_EN[esSchool] ?? esSchool;
  if (lang === "pt") return SCHOOL_PT[esSchool] ?? esSchool;
  return esSchool;
}
